import requests
import json

RABBITMQ_API_URL = 'http://localhost:15672/api'
USERNAME = 'your_username'
PASSWORD = 'your_password'

def create_vhost(vhost_name):
    url = f'{RABBITMQ_API_URL}/vhosts/{vhost_name}'
    response = requests.put(url, auth=(USERNAME, PASSWORD))
    return response.status_code, response.json()

def set_permissions(vhost_name, user, permissions):
    url = f'{RABBITMQ_API_URL}/users/{user}/permissions/{vhost_name}'
    response = requests.put(url, auth=(USERNAME, PASSWORD), data=json.dumps(permissions),
                            headers={'Content-Type': 'application/json'})
    return response.status_code, response.json()

def main():
    vhosts = ['app1', 'app2', 'app3']
    user_permissions = {
        'write': '.*',
        'read': '.*',
        'configure': '.*'
    }

    for vhost in vhosts:
        status_code, _ = create_vhost(vhost)
        if status_code == 204:
            print(f'Vhost {vhost} created successfully.')
        else:
            print(f'Failed to create vhost {vhost}. Status code: {status_code}')

        status_code, _ = set_permissions(vhost, 'app_user', user_permissions)
        if status_code == 204:
            print(f'Permissions set for user "app_user" on vhost {vhost}.')
        else:
            print(f'Failed to set permissions for user "app_user" on vhost {vhost}. Status code: {status_code}')

if __name__ == '__main__':
    main()